import{c as l,$ as c,Q as a,j as h,m as o,h as n,ax as t,n as s,o as r,S as d}from"./chunks/framework.BCN3hdhj.js";const v=JSON.parse('{"title":"The Mirror Test: When the Scorer Started Inventing Rules","description":"","frontmatter":{},"headers":[],"relativePath":"case-studies/2026-04-24-mirror-test.md","filePath":"case-studies/2026-04-24-mirror-test.md","lastUpdated":null}'),u={name:"case-studies/2026-04-24-mirror-test.md"};function p(g,e,m,f,b,y){const i=c("Mermaid");return a(),h("div",null,[e[3]||(e[3]=o('<h1 id="the-mirror-test-when-the-scorer-started-inventing-rules" tabindex="-1">The Mirror Test: When the Scorer Started Inventing Rules <a class="header-anchor" href="#the-mirror-test-when-the-scorer-started-inventing-rules" aria-label="Permalink to &quot;The Mirror Test: When the Scorer Started Inventing Rules&quot;">​</a></h1><blockquote><p><strong>Disclosure</strong>: This case study was written by Claude (Opus 4.7) at the request of NLPM&#39;s maintainer <a href="https://github.com/xiaolai" target="_blank" rel="noreferrer">xiaolai</a>. The subject of the audit — the NLPM scorer agent — is itself powered by Claude (Sonnet 4.6 at time of writing). The author, the tool, and the auditee are all instances of the same model family. Readers should weigh that accordingly.</p></blockquote><hr><h2 id="the-context" tabindex="-1">The Context <a class="header-anchor" href="#the-context" aria-label="Permalink to &quot;The Context&quot;">​</a></h2><p>Over the past three weeks, NLPM&#39;s audit pipeline visited seven external Claude Code plugin repositories. It scored <code>wshobson/agents</code>, <code>sickn33/antigravity-awesome-skills</code>, <code>hesreallyhim/awesome-claude-code</code>, <code>jeremylongshore/claude-code-plugins-plus-skills</code>, <code>nyldn/claude-octopus</code>, and filed bug-fix PRs where maintainers accepted them. Each engagement generated findings, each finding carried a rule number, each rule number pointed to a line in <code>skills/nlpm/scoring/SKILL.md</code> — a 100-point penalty rubric that starts at 100 and subtracts for documented defects.</p><p>The rubric is the judge. Seven external repos got judged.</p><p>Today, on 2026-04-24, we pointed the rubric inward. <code>/nlpm:score</code> ran across all 18 plugins in the xiaolai marketplace, including NLPM itself. This is the plugin that audits other plugins, now auditing itself — a judge reading its own judgment.</p><p>The judge began making things up.</p><hr><h2 id="the-run" tabindex="-1">The Run <a class="header-anchor" href="#the-run" aria-label="Permalink to &quot;The Run&quot;">​</a></h2><p><strong>Date</strong>: 2026-04-24 | <strong>Plugins audited</strong>: 18 | <strong>Aggregate score</strong>: 82.5/100</p><p>All 18 plugins scored in the 70–98 range. On the surface, a clean result: nothing below the 70 threshold, no security red flags, mostly actionable findings. But while reading the per-plugin reports, the maintainer noticed a pattern across seven of them.</p><p><strong>The scorer was reporting findings that could not be traced to any documented penalty.</strong></p><p>Not a handful of edge cases. Seven plugins, five distinct categories, each category reported across multiple files with confident rule-number assertions. At first glance, well-formed findings. On second reading, phantom ones.</p><hr><h2 id="what-we-found" tabindex="-1">What We Found <a class="header-anchor" href="#what-we-found" aria-label="Permalink to &quot;What We Found&quot;">​</a></h2><p>Each row below documents a finding type the scorer reported. For each, the &quot;why it is invalid&quot; column cites the specific line of specific documentation that rules it out.</p><table tabindex="0"><thead><tr><th>#</th><th>Hallucinated finding</th><th>Actual convention</th><th>Plugins affected</th></tr></thead><tbody><tr><td>FP1</td><td>&quot;Skill missing <code>namespace:</code> field&quot;</td><td><code>conventions</code> §5 lists only <code>name</code>, <code>description</code>, <code>version</code>, <code>globs</code> — no <code>namespace</code></td><td>tdd-guardian (7 skills flagged)</td></tr><tr><td>FP2</td><td>&quot;plugin.json missing <code>hooks</code>/<code>skills</code> registration blocks&quot; (expecting inline arrays)</td><td><code>conventions</code> §1 defines these as optional <strong>path strings</strong>, never inline registration</td><td>claude-english-buddy, docs-guardian, tdd-guardian</td></tr><tr><td>FP3</td><td>&quot;<code>AskUserQuestion</code> is an undocumented tool&quot;</td><td>Real Claude Code built-in — not catalogued anywhere in <code>conventions</code></td><td>nlpm, echo-sleuth</td></tr><tr><td>FP4</td><td>&quot;Agent missing <code>skills:</code> when body references skill knowledge&quot;</td><td>Intentional omission — vague-scanner documented as having no skills per <code>CLAUDE.md:28</code></td><td>nlpm (vague-scanner)</td></tr><tr><td>FP5</td><td>&quot;plugin.json missing <code>engines</code> / <code>minClaudeVersion</code> / <code>main</code>&quot;</td><td>No such fields exist in the schema — not listed as required or optional anywhere</td><td>three unpublished in-development plugins</td></tr></tbody></table><p>The pattern is specific enough to name. Four of the five involve missing fields — fields the rubric has no claim about. One (FP3) involves a real tool the scorer failed to recognize. All five have the same shape: the scorer applied a schema the scorer imagined.</p><h3 id="reading-the-evidence" tabindex="-1">Reading the Evidence <a class="header-anchor" href="#reading-the-evidence" aria-label="Permalink to &quot;Reading the Evidence&quot;">​</a></h3><p><strong>FP1 — <code>namespace:</code> on skills.</strong> The skill frontmatter fields documented in <code>conventions</code> §5 are <code>name</code>, <code>description</code>, <code>version</code>, <code>globs</code>. No <code>namespace</code>. The scoring rubric&#39;s Skills table cites the same four. There is no penalty row anywhere for <code>namespace</code>. Yet seven tdd-guardian skills were flagged for its absence.</p><p><strong>FP2 — inline <code>hooks</code>/<code>skills</code> blocks in plugin.json.</strong> <code>conventions</code> §1 is explicit: <code>hooks</code> and <code>skills</code> are &quot;Component path fields (all optional, string or string[]).&quot; They are pointers to files, not inline configuration. The scorer&#39;s finding assumed a schema where plugin.json contains inline registration arrays — a schema no Claude Code plugin has ever had.</p><p><strong>FP3 — <code>AskUserQuestion</code> undocumented.</strong> The tool exists. It is a native Claude Code built-in. It is available in the session where this article was written. <code>conventions</code> did not have a tool catalog before today, so the scorer had no citable authority to check against. Instead of reporting &quot;no catalog exists,&quot; it reported &quot;tool is undocumented&quot; — a finding that sounds rule-based but is not.</p><p><strong>FP4 — agent missing <code>skills:</code>.</strong> The vague-scanner agent is documented in the plugin&#39;s own CLAUDE.md with the explicit annotation <code>(no skills)</code>. It is a mechanical word-counter; it has no judgment to delegate. The scorer penalized it for the absence.</p><p><strong>FP5 — <code>engines</code> / <code>minClaudeVersion</code> / <code>main</code> in plugin.json.</strong> These are foreign conventions. <code>engines</code> and <code>main</code> come from Node.js <code>package.json</code>; <code>minClaudeVersion</code> is not documented in any system this rubric describes. None appear in <code>conventions</code> §1 or anywhere in the rubric. The scorer synthesized a composite schema and applied it.</p><hr><h2 id="the-mechanism" tabindex="-1">The Mechanism <a class="header-anchor" href="#the-mechanism" aria-label="Permalink to &quot;The Mechanism&quot;">​</a></h2><p>Why would a rule-based scorer, asked to apply a fixed rubric, invent rules?</p><p>The rubric is markdown text passed into a Claude model. Claude is not a rule engine; it is a model that has absorbed many rubrics across many domains and makes inferences about which apply. When asked to score a <code>plugin.json</code>, it does not execute <code>conventions</code> §1 as a deterministic parser would. It reads <code>conventions</code> §1, decides the text describes the same thing as thousands of <code>package.json</code> files it has seen, and offers suggestions consistent with the combined schema.</p><p>In most calls, this is a feature. A model that notices a missing <code>author</code> field in <code>plugin.json</code> because &quot;most JSON manifests include one&quot; is useful — even when the rubric is silent, the inference may still be right.</p><p>In rare calls, it is a defect. A model that reports &quot;plugin.json missing <code>engines:</code> field&quot; because &quot;most npm-style manifests have one&quot; is applying a schema the rubric does not describe and the system does not require.</p><p>The inference path is the same. Whether a given suggestion lands on the useful side or the defective side depends on how closely the rubric&#39;s schema matches the model&#39;s absorbed priors. When they match, judgment fills in gaps the rubric left. When they diverge, judgment fills in gaps the rubric wanted left open.</p><h3 id="a-plausible-trigger" tabindex="-1">A Plausible Trigger <a class="header-anchor" href="#a-plausible-trigger" aria-label="Permalink to &quot;A Plausible Trigger&quot;">​</a></h3><p>The NLPM scorer runs on the <code>claude-code-action</code> default model — currently Sonnet 4.6, previously Sonnet 4.5, before that earlier Sonnet revisions. Model upgrades arrive silently; the scorer pipeline picks them up without version-pinning. Each upgrade shifts the model&#39;s absorbed priors without the rubric shifting in response.</p><p>This is a hypothesis, not a measurement — NLPM&#39;s audit logs do not go back far enough to prove when FP1–FP5 first appeared. But the shape of the observation is consistent with model drift. A more inventive model produces more inventive findings. Without a rubric that explicitly denies the inventions, the inventions get reported.</p><p><strong>The meta-pattern</strong>: as the evaluator gets smarter, the rulebook must get more defensive. A rulebook is not a complete specification of what the rules are; it is an incomplete statement whose gaps the model fills in. Smarter models fill in more gaps, more creatively — for better and worse.</p><hr><h2 id="the-fix" tabindex="-1">The Fix <a class="header-anchor" href="#the-fix" aria-label="Permalink to &quot;The Fix&quot;">​</a></h2><p>Three documentation layers and one test layer were added. Each addresses a different gap the model fills in unsupervised.</p>',39)),(a(),n(d,null,{default:t(()=>[r(i,{id:"mermaid-196",class:"mermaid-diagram",graph:"flowchart%20TB%0A%20%20%20%20A%5BScorer%20receives%20artifact%5D%0A%20%20%20%20A%20--%3E%20B%7BRule%20cited%20in%3Cbr%2F%3Escoring%20rubric%3F%7D%0A%20%20%20%20B%20--%3E%7CNo%7C%20D%5BDrop%20finding%5D%0A%20%20%20%20B%20--%3E%7CYes%7C%20C%7BField%20listed%20in%3Cbr%2F%3Econventions%20schema%3F%7D%0A%20%20%20%20C%20--%3E%7CNo%7C%20D%0A%20%20%20%20C%20--%3E%7CYes%7C%20E%7BOmission%20documented%3Cbr%2F%3Eas%20intentional%3F%7D%0A%20%20%20%20E%20--%3E%7CYes%7C%20D%0A%20%20%20%20E%20--%3E%7CNo%7C%20F%7BTool%20valid%20per%3Cbr%2F%3E%C2%A714%20catalog%3F%7D%0A%20%20%20%20F%20--%3E%7CNo%7C%20D%0A%20%20%20%20F%20--%3E%7CYes%7C%20G%5BReport%20finding%5D%0A%0A%20%20%20%20style%20D%20fill%3A%23fee2e2%2Cstroke%3A%23ef4444%0A%20%20%20%20style%20G%20fill%3A%23dcfce7%2Cstroke%3A%2322c55e%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[s(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=o('<h3 id="layer-1-citable-facts" tabindex="-1">Layer 1: Citable Facts <a class="header-anchor" href="#layer-1-citable-facts" aria-label="Permalink to &quot;Layer 1: Citable Facts&quot;">​</a></h3><p><code>skills/nlpm/conventions/SKILL.md</code> gains §14, a tool catalog. Every Claude Code built-in tool is named: <code>Read</code>, <code>Write</code>, <code>Edit</code>, <code>MultiEdit</code>, <code>NotebookEdit</code>, <code>Glob</code>, <code>Grep</code>, <code>Bash</code>, <code>BashOutput</code>, <code>KillBash</code>, <code>Task</code>, <code>WebFetch</code>, <code>WebSearch</code>, <code>AskUserQuestion</code>, <code>TodoWrite</code>, <code>SlashCommand</code>. MCP tools follow a named pattern. Case-sensitivity is stated.</p><p>The scorer now has a document to cite when asked &quot;is this tool valid?&quot;</p><h3 id="layer-2-behavioral-gate" tabindex="-1">Layer 2: Behavioral Gate <a class="header-anchor" href="#layer-2-behavioral-gate" aria-label="Permalink to &quot;Layer 2: Behavioral Gate&quot;">​</a></h3><p><code>agents/scorer.md</code> gains a &quot;Do Not Invent Findings&quot; section. Four checks apply before any finding is reported: rubric check, schema check, intent check, tool catalog check. If a finding fails any of them, it is dropped.</p><p>The section also enumerates the exact fields that must not be flagged as missing: <code>namespace:</code> on skills, <code>main:</code> / <code>engines:</code> / <code>minClaudeVersion:</code> on <code>plugin.json</code>, inline <code>hooks:</code> / <code>skills:</code> blocks, <code>tools:</code> on reference-only skills, <code>commentary:</code> on agent examples. Five mistakes named. No new rules added. The rubric stays the rubric; the agent stops filling in its gaps.</p><h3 id="layer-3-explicit-denials-in-the-rubric" tabindex="-1">Layer 3: Explicit Denials in the Rubric <a class="header-anchor" href="#layer-3-explicit-denials-in-the-rubric" aria-label="Permalink to &quot;Layer 3: Explicit Denials in the Rubric&quot;">​</a></h3><p><code>skills/nlpm/scoring/SKILL.md</code> gains a &quot;Known False Positive Patterns&quot; table in its Scope Note. The six patterns that have been observed or are plausibly next are listed, with the reason each is invalid. The final row addresses a pattern we did not apply but could foresee: &quot;plugin.json description shorter than sibling marketplace.json description&quot; — desynchronization, not defect.</p><p>The rubric now states what it does not rule on, in addition to what it does.</p><h3 id="layer-4-regression-tests" tabindex="-1">Layer 4: Regression Tests <a class="header-anchor" href="#layer-4-regression-tests" aria-label="Permalink to &quot;Layer 4: Regression Tests&quot;">​</a></h3><p><code>.nlpm-test/scorer.spec.md</code> gains five new scenarios, one per observed false positive. Each follows the Given/When/Then form: given the specific structure that was hallucinated against, when scored, then no finding is emitted for the hallucinated category.</p><p>If a future model reintroduces any of the five, <code>/nlpm:test</code> will catch it.</p><h3 id="the-four-layer-logic" tabindex="-1">The Four-Layer Logic <a class="header-anchor" href="#the-four-layer-logic" aria-label="Permalink to &quot;The Four-Layer Logic&quot;">​</a></h3><p>The four layers attack different gaps:</p>',14)),(a(),n(d,null,{default:t(()=>[r(i,{id:"mermaid-239",class:"mermaid-diagram",graph:"graph%20LR%0A%20%20%20%20subgraph%20Conv%20%5B%22conventions%20%C2%A714%22%5D%0A%20%20%20%20%20%20%20%20C1%5BCitable%20facts%3A%3Cbr%2F%3Ewhat%20tools%20exist%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20Scorer%20%5B%22scorer.md%20gate%22%5D%0A%20%20%20%20%20%20%20%20S1%5BProcedure%3A%3Cbr%2F%3Echeck%20before%20reporting%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20Rubric%20%5B%22scoring%20%C2%A7Scope%20Note%22%5D%0A%20%20%20%20%20%20%20%20R1%5BBoundaries%3A%3Cbr%2F%3Eexplicit%20denials%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20Test%20%5B%22scorer.spec.md%22%5D%0A%20%20%20%20%20%20%20%20T1%5BRegression%3A%3Cbr%2F%3Ecatch%20future%20drift%5D%0A%20%20%20%20end%0A%0A%20%20%20%20C1%20--%3E%7Cfacts%7C%20S1%0A%20%20%20%20R1%20--%3E%7Cboundaries%7C%20S1%0A%20%20%20%20S1%20--%3E%7Cbehavior%7C%20T1%0A%0A%20%20%20%20style%20Conv%20fill%3A%23e0f2fe%2Cstroke%3A%230284c7%0A%20%20%20%20style%20Scorer%20fill%3A%23fef3c7%2Cstroke%3A%23d97706%0A%20%20%20%20style%20Rubric%20fill%3A%23ede9fe%2Cstroke%3A%237c3aed%0A%20%20%20%20style%20Test%20fill%3A%23dcfce7%2Cstroke%3A%2316a34a%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[s(" Loading... ",-1)])]),_:1})),e[5]||(e[5]=o('<p>No single layer is sufficient. The tool catalog without the behavioral gate produces a scorer that reads it but does not check it. The behavioral gate without the rubric boundary produces a scorer that rejects findings but cannot explain why. The rubric boundary without the regression suite produces a fix that regresses silently on the next model upgrade. Stacking all four leaves no obvious hole.</p><hr><h2 id="the-re-audit" tabindex="-1">The Re-Audit <a class="header-anchor" href="#the-re-audit" aria-label="Permalink to &quot;The Re-Audit&quot;">​</a></h2><p>A rubric update is a claim, not a verification. Hours after the v0.7.6 commit, the scorer was pointed back at the six published plugins in the xiaolai marketplace — including NLPM itself — to see whether the four-layer defense held on real targets.</p><p>Six parallel scoring runs. Each loaded the v0.7.6 rubric from disk and audited one plugin. For each run, the five FP patterns were named explicitly as regression checks: &quot;did this category reappear? yes/no.&quot;</p><table tabindex="0"><thead><tr><th>Plugin</th><th style="text-align:right;">Score</th><th style="text-align:right;">Artifacts</th><th>FP1</th><th>FP2</th><th>FP3</th><th>FP4</th><th>FP5</th></tr></thead><tbody><tr><td>nlpm (self)</td><td style="text-align:right;">96</td><td style="text-align:right;">32</td><td>clean</td><td>clean</td><td>clean</td><td>clean</td><td>clean</td></tr><tr><td>claude-english-buddy</td><td style="text-align:right;">99</td><td style="text-align:right;">10</td><td>clean</td><td>clean</td><td>clean</td><td>clean</td><td>clean</td></tr><tr><td>grill</td><td style="text-align:right;">96</td><td style="text-align:right;">10</td><td>clean</td><td>clean</td><td>clean</td><td>clean</td><td>clean</td></tr><tr><td>docs-guardian</td><td style="text-align:right;">99</td><td style="text-align:right;">26</td><td>clean</td><td>clean</td><td>clean</td><td>clean</td><td>clean</td></tr><tr><td>tdd-guardian</td><td style="text-align:right;">95</td><td style="text-align:right;">19</td><td>clean</td><td>clean</td><td>clean</td><td>clean</td><td>clean</td></tr><tr><td>echo-sleuth</td><td style="text-align:right;">98</td><td style="text-align:right;">19</td><td>clean</td><td>clean</td><td>clean</td><td>clean</td><td>clean</td></tr></tbody></table><p>Thirty regression checks — five FPs across six plugins — all clean. The exact cases that would have triggered FPs under v0.7.5 passed silently: tdd-guardian&#39;s seven skills without <code>namespace:</code>, <code>AskUserQuestion</code> declared in three plugins&#39; <code>allowed-tools</code>, vague-scanner omitting <code>skills:</code> by design. The gate held where it mattered.</p><p>But the re-audit surfaced two calibration items the first pass had not anticipated. A working rubric is one that keeps surfacing its own edges.</p><h3 id="r01-penalizes-its-own-definition" tabindex="-1">R01 Penalizes Its Own Definition <a class="header-anchor" href="#r01-penalizes-its-own-definition" aria-label="Permalink to &quot;R01 Penalizes Its Own Definition&quot;">​</a></h3><p>Four artifacts in NLPM hit R01&#39;s −20 vague-quantifier cap — not because they contain vague language, but because they <em>enumerate the vocabulary R01 flags</em>. The scorer has to list the eleven words in order to check for them. The rubric row defining R01 has to list them to define itself. Documentation that teaches R01 lists them by way of explaining.</p><p>R01 is mechanical by design — &quot;each occurrence of &#39;appropriate&#39;, &#39;relevant&#39;, &#39;as needed&#39;...&quot; — and does not distinguish between a word <em>used</em> and a word <em>mentioned</em>. Backticks do not save you. Code fences do not save you. Quoting R01&#39;s vocabulary in a comma-separated sentence earns a full −20 cap hit.</p><p>This is the rubric operating as specified. It is also a category error: a rubric that penalizes its own definition for quoting itself is measuring its own reflection. The fix is a mention-vs-use distinction — exempt occurrences inside inline code spans, fenced code blocks, and literal enumerations of the vocabulary.</p><h3 id="the-agent-task-alias-gap" tabindex="-1">The <code>Agent</code> / <code>Task</code> Alias Gap <a class="header-anchor" href="#the-agent-task-alias-gap" aria-label="Permalink to &quot;The `Agent` / `Task` Alias Gap&quot;">​</a></h3><p><code>commands/security-scan.md</code> declares <code>Agent</code> in its <code>allowed-tools</code>. The §14 tool catalog added in v0.7.6 lists the agent-dispatch tool as <code>Task</code>. The rest of the ecosystem — <code>grill</code>, <code>docs-guardian</code>, <code>tdd-guardian</code> — also uses <code>Task</code>. Either <code>Agent</code> is a deprecated alias or a local mistake; no rubric row today penalizes undocumented tools, so the four-step gate correctly drops the finding. But the artifact is inconsistent with its own plugin&#39;s catalog — a case the gate notices and cannot act on.</p><p>Two follow-ups surface: fix <code>security-scan.md</code> to match §14, and consider whether an &quot;unknown-tool-in-allowed-tools&quot; penalty row should exist. The second is deferrable — §14 is less than a day old, and may itself be incomplete.</p><h3 id="what-the-re-audit-confirmed" tabindex="-1">What the Re-Audit Confirmed <a class="header-anchor" href="#what-the-re-audit-confirmed" aria-label="Permalink to &quot;What the Re-Audit Confirmed&quot;">​</a></h3><p>The model-drift hypothesis remains unproven (the audit logs are still empty). But the re-audit produced adjacent evidence: under v0.7.6, the scorer stops inventing the five categories it was inventing earlier today. The four-layer defense works against the specific patterns it was designed to block. New structural issues — like R01 self-reference — were surfaced by the audit process itself, not by human review. That is what a working rubric is supposed to do.</p><hr><h2 id="the-mirror-test" tabindex="-1">The Mirror Test <a class="header-anchor" href="#the-mirror-test" aria-label="Permalink to &quot;The Mirror Test&quot;">​</a></h2><p>Everything written here happened inside one conversation with Claude. The case study was written by Claude. The scorer is run by Claude. The rubric was written by a prior Claude session. The PRs to external repos were drafted by Claude. The plugin under audit was built by — or at least with — Claude.</p><p>At each stage, a human held the rudder. The maintainer flagged the seven plugins. The maintainer wrote the self-update proposal. The maintainer discarded unrelated working-tree changes before approving the update. The maintainer is reading this paragraph now, deciding whether it is accurate. No step in the chain ran without a human checkpoint.</p><p>But the question the engagement poses is structural. If the scorer and the rubric are both authored by the same family of models, who catches the drift when the models drift? Today, the answer was &quot;a human running <code>/nlpm:score</code> on his own work and noticing the findings did not match the rubric.&quot; That works. It does not scale.</p><p>The new layers are a partial answer. They give the scorer a rubric it can citably verify against, and a regression suite that will fire when it cannot. They do not solve the underlying problem — that a model reading a rubric is not the same as a rule engine executing one, and a rulebook written to be readable is not the same as a rulebook written to be complete.</p><p>The mirror test is not a one-time check. It is the realization that as the evaluator evolves, the thing being evaluated needs to evolve to match — including when the thing being evaluated is the evaluator.</p><hr><h2 id="timeline" tabindex="-1">Timeline <a class="header-anchor" href="#timeline" aria-label="Permalink to &quot;Timeline&quot;">​</a></h2>',26)),(a(),n(d,null,{default:t(()=>[r(i,{id:"mermaid-497",class:"mermaid-diagram",graph:"gantt%0A%20%20%20%20title%20NLPM%20Self-Audit%20%E2%80%94%202026-04-24%0A%20%20%20%20dateFormat%20HH%3Amm%0A%20%20%20%20axisFormat%20%25H%3A%25M%0A%0A%20%20%20%20section%20Audit%0A%20%20%20%20%2Fnlpm%3Ascore%20across%2018%20plugins%20%20%20%20%20%20%20%3Adone%2C%20a1%2C%2005%3A00%2C%2070m%0A%20%20%20%20Maintainer%20flags%20five%20FP%20patterns%20%20%20%3Amilestone%2C%2006%3A20%2C%200m%0A%0A%20%20%20%20section%20Analysis%0A%20%20%20%20Trace%20each%20FP%20to%20documentation%20%20%20%20%20%20%3Adone%2C%2006%3A20%2C%2030m%0A%20%20%20%20Self-update%20proposal%20written%20%20%20%20%20%20%20%20%3Adone%2C%2006%3A36%2C%201m%0A%0A%20%20%20%20section%20Fix%0A%20%20%20%20Verify%20claims%20line-by-line%20%20%20%20%20%20%20%20%20%20%3Adone%2C%2008%3A30%2C%2020m%0A%20%20%20%20Apply%204%20updates%20%2B%20version%20bump%20%20%20%20%20%20%3Adone%2C%2008%3A50%2C%2020m%0A%20%20%20%20Write%20case%20study%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%3Adone%2C%2009%3A10%2C%2060m%0A%0A%20%20%20%20section%20Verify%0A%20%20%20%20Re-audit%206%20published%20plugins%20%20%20%20%20%20%20%20%3Adone%2C%2010%3A30%2C%2045m%0A%20%20%20%20Record%2030%2F30%20FP%20regression%20passes%20%20%20%3Amilestone%2C%2011%3A15%2C%200m%0A%20%20%20%20Surface%20R01%20self-ref%20%2B%20Agent%2FTask%20%20%20%3Amilestone%2C%2011%3A20%2C%200m%0A%20%20%20%20Update%20case%20study%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%20%3Adone%2C%2011%3A20%2C%2030m%0A"})]),fallback:t(()=>[...e[2]||(e[2]=[s(" Loading... ",-1)])]),_:1})),e[6]||(e[6]=o('<p>Approximate times; proposal timestamp from file mtime. Same-day from audit to applied fix to re-audit verification to published case study.</p><hr><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><p><strong>The model-upgrade hypothesis is unverified.</strong> NLPM&#39;s audit logs (<code>findings.jsonl</code>, <code>disagreements.jsonl</code>) are empty at the time of writing; there is no historical data showing when FP1–FP5 first appeared. The correlation with model upgrades is plausible but not established.</p><p><strong>The fix targets the five observed patterns.</strong> Other hallucinated categories may exist that today&#39;s audit did not surface. The four-step behavioral gate catches the class (uncitable findings), but the explicit-denial table only lists what has been seen. The re-audit covered six published plugins and surfaced two new calibration items (R01 self-reference, Agent/Task alias) — future audits will likely surface more.</p><p><strong>The formal test suite was not executed.</strong> <code>.nlpm-test/scorer.spec.md</code> describes expected behavior; <code>/nlpm:test</code> evaluates the scorer&#39;s output against the specs. The re-audit across the six published plugins validated FP1–FP5 regression behavior manually, but the specs themselves were not run under the official test harness. That remains a next step.</p><p><strong>The case study is self-authored.</strong> Claude wrote the scorer, the fix, this article, and the re-audit sub-agents. The conflict of interest is structural, not resolvable from inside the same model family. External review of this engagement is available only as a future artifact.</p><p><strong>The PRs to external repos during the preceding three weeks used the v0.7.5 scorer.</strong> Whether any of those PRs carried FP1–FP5 findings is a question for a separate audit of the outgoing PR record. The re-audit covered only internal plugins.</p><hr><h2 id="significance" tabindex="-1">Significance <a class="header-anchor" href="#significance" aria-label="Permalink to &quot;Significance&quot;">​</a></h2><p>The engagement produced four surgical edits (~109 lines) and a version bump from 0.7.5 to 0.7.6. No structural rewrites, no new commands, no new agents. The thing that changed is what the scorer is allowed to say.</p><p>Seven external engagements taught NLPM how to audit. The eighth — turning the audit inward — taught it what it had been getting wrong about itself. A scoring system that cannot evaluate its own output honestly is limited in what it can teach others. A scoring system that can is useful, within the limits of the rubric it stands on.</p><p>The broader pattern — rule systems paired with increasingly capable evaluators — is not unique to NLPM. Any automated-review pipeline that pairs a static rulebook with an evolving model runs the same risk. The fix is not to pin the model or freeze the rulebook; both are living artifacts. The fix is to write the rulebook so that the gaps it leaves are explicit gaps, not invitations to invent.</p><p>NLPM now names some of its own gaps. It will likely need to name more of them, on a schedule that tracks model upgrades rather than calendar quarters. The mirror test, as a discipline, is: run the scorer on its own work every time the underlying model moves. What comes back is either the rubric working — or the rubric&#39;s next revision, writing itself.</p><hr><h2 id="next-cycle" tabindex="-1">Next Cycle <a class="header-anchor" href="#next-cycle" aria-label="Permalink to &quot;Next Cycle&quot;">​</a></h2><p>Two follow-up items surfaced by the re-audit, targeted for NLPM v0.7.7:</p><ol><li><strong>R01 mention-vs-use distinction.</strong> Exempt vague-word occurrences inside inline code spans, fenced code blocks, and literal enumerations of the vocabulary. Touches <code>skills/nlpm/scoring/SKILL.md</code> (R01 row), <code>skills/nlpm/rules/SKILL.md</code> (R01 definition), and <code>agents/vague-scanner.md</code> (mechanical filter). Recovers the ~20 points that four NLPM artifacts lose structurally for quoting R01.</li><li><strong><code>commands/security-scan.md</code>: <code>Agent</code> → <code>Task</code>.</strong> Align the declared tool with §14 and ecosystem convention. One-character fix.</li></ol><p>Deferred: adding a penalty row for unknown tools in <code>allowed-tools</code>. The §14 catalog is less than a day old and may itself be incomplete; letting it stabilize for a release cycle before making the gate bite on tool declarations.</p><hr><h2 id="what-changed" tabindex="-1">What Changed <a class="header-anchor" href="#what-changed" aria-label="Permalink to &quot;What Changed&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File</th><th>Change</th></tr></thead><tbody><tr><td><code>skills/nlpm/conventions/SKILL.md</code></td><td>Added §14 Claude Code Tool Catalog (16 built-in tools + MCP pattern)</td></tr><tr><td><code>agents/scorer.md</code></td><td>Added &quot;Do Not Invent Findings&quot; section with 4-step check</td></tr><tr><td><code>skills/nlpm/scoring/SKILL.md</code></td><td>Added &quot;Known False Positive Patterns&quot; table to Scope Note</td></tr><tr><td><code>.nlpm-test/scorer.spec.md</code></td><td>Added 5 regression scenarios (one per observed FP)</td></tr><tr><td><code>.claude-plugin/plugin.json</code></td><td>Version 0.7.5 → 0.7.6</td></tr></tbody></table><p><strong>Total</strong>: 109 lines added, 1 line removed. No deletions of prior rubric content.</p>',23))])}const A=l(u,[["render",p]]);export{v as __pageData,A as default};
